  1	import React, { FC, ReactNode, useCallback } from 'react';
  2	import { useParams } from 'react-router-dom-v5-compat';
  3	
  4	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
  5	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
  6	import { t } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import { FormGroup, SelectOption } from '@patternfly/react-core';
  8	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
  9	
 10	import { SOURCE_OPTIONS_IDS, SOURCE_TYPES } from '../../utils/constants';
 11	
 12	const getSourceOption = (source: SOURCE_OPTIONS_IDS, ns: string) => {
 13	  switch (source) {
 14	    case SOURCE_TYPES.defaultSource:
 15	      return (
 16	        <SelectOption
 17	          description={t('Use the default Template disk source')}
 18	          value={SOURCE_TYPES.defaultSource}
 19	        >
 20	          <span data-test-id={SOURCE_TYPES.defaultSource}>{t('Default')}</span>
 21	        </SelectOption>
 22	      );
 23	    case SOURCE_TYPES.pvcSource:
 24	      return (
 25	        <SelectOption
 26	          description={t(
 27	            'Select an existing persistent volume claim already available on the cluster and clone it.',
 28	          )}
 29	          value={SOURCE_TYPES.pvcSource}
 30	        >
 31	          <span data-test-id={SOURCE_TYPES.pvcSource}>{t('PVC (clone PVC)')}</span>
 32	        </SelectOption>
 33	      );
 34	    case SOURCE_TYPES.httpSource:
 35	      return (
 36	        <SelectOption
 37	          description={t('Import content via URL (HTTP or HTTPS endpoint).')}
 38	          value={SOURCE_TYPES.httpSource}
 39	        >
 40	          <span data-test-id={SOURCE_TYPES.httpSource}>{t('URL (creates PVC)')}</span>
 41	        </SelectOption>
 42	      );
 43	    case SOURCE_TYPES.registrySource:
 44	      return (
 45	        <SelectOption
 46	          description={t('Import content via container registry.')}
 47	          value={SOURCE_TYPES.registrySource}
 48	        >
 49	          <span data-test-id={SOURCE_TYPES.registrySource}>{t('Registry (ContainerDisk)')}</span>
 50	        </SelectOption>
 51	      );
 52	    case SOURCE_TYPES.uploadSource:
 53	      return (
 54	        <SelectOption
 55	          onClick={() =>
 56	            window
 57	              .open(`/k8s/ns/${ns || DEFAULT_NAMESPACE}/persistentvolumeclaims/~new/data`, '_blank')
 58	              .focus()
 59	          }
 60	          description={t('Upload new file using the "Upload data to Persistent Volume Claim" page')}
 61	          value={SOURCE_TYPES.uploadSource}
 62	        >
 63	          {t('Upload (Upload a new file to a PVC)')} <ExternalLinkAltIcon />
 64	        </SelectOption>
 65	      );
 66	    default:
 67	      return;
 68	  }
 69	};
 70	
 71	type SelectSourceOptionProps = {
 72	  label: ReactNode;
 73	  onSelectSource: (selection: SOURCE_OPTIONS_IDS) => void;
 74	  options: SOURCE_OPTIONS_IDS[];
 75	  selectedSource: SOURCE_OPTIONS_IDS;
 76	};
 77	
 78	const SelectSourceOption: FC<SelectSourceOptionProps> = ({
 79	  label,
 80	  onSelectSource,
 81	  options,
 82	  selectedSource,
 83	}) => {
 84	  const { ns } = useParams<{ ns: string }>();
 85	
 86	  const onSelect = useCallback(
 87	    (_, selection) => {
 88	      if (selection !== SOURCE_TYPES.uploadSource) onSelectSource(selection);
 89	    },
 90	    [onSelectSource],
 91	  );
 92	
 93	  return (
 94	    <FormGroup
 95	      className="disk-source-form-group select-source-option"
 96	      fieldId="disk-source-required-disk"
 97	      isRequired
 98	      label={label}
 99	    >
100	      <FormPFSelect
101	        onSelect={onSelect}
102	        placeholder={t('Select boot source')}
103	        selected={selectedSource}
104	      >
105	        <SelectOption isDisabled key={0} value="Select a title">
106	          Select a title
107	        </SelectOption>
108	        {options.map((option) => getSourceOption(option, ns))}
109	      </FormPFSelect>
110	    </FormGroup>
111	  );
112	};
113	
114	export default SelectSourceOption;

